def BFS(graph, start):
    """Returns a list of nodes in order of visiting."""
    queue = [start]
    visited = []
    while queue:
        current = queue.pop(0)
        visited.append(current)
        for next in graph[current]:
            if next not in visited and next not in queue:
                queue.append(next)
    return visited

def BFS_path(graph, start, end):
    """Returns the shortest path between start and end."""
    queue = BFS(graph, start)
    path = [end]
    while queue and path[-1] != start:
        current = queue.pop(0)
        for next in graph[current]:
            if next in path:
                continue
            path.append(next)
    return path
